import { Router } from "express";
import { listBucketController, createBucketController, toggleBucketController, deleteBucketController, listWalletController, createWalletController, deleteWalletController, listChallengesController, createChallengeController, checkinChallengeController, deleteChallengeController, addAlbumPhotoController, addSongController, createAlbumController, createCalendarEventController, createQuizGameController, createLetterController, createMemoryController, createRoomQuizController, createRoomController, createTaskController, deleteAlbumPhotoController, deleteCalendarEventController, deleteLetterController, deleteMemoryController, deleteTaskController, getQuizGamePlayController, getQuizGameReportController, getRoomController, joinRoomController, statsController, getGameController, gameMoveController, inviteGameController, acceptGameController, declineGameController, playRpsController, surrenderGameController, listAlbumsController, listCalendarEventsController, listLettersController, listMemoriesController, listNotificationsController, openLetterController, listQuizGamesController, listSongsController, listTasksController, markAllNotificationsReadController, markNotificationReadController, markTaskDoneController, pinLoveNoteController, removeSongController, setMoodController, submitAnswerController, submitQuizGameAttemptController, submitRoomQuizAnswerController, summaryController, todayMoodsController, todayQuestionController, updateCalendarEventController, updateLetterController, updateMemoryController, updateRoomAvatarController, updateRoomController, updateSongController, updateTaskController } from "../controllers/coupleController.js";
import { requireAuth } from "../middlewares/auth.js";
import { rateLimit } from "../middlewares/rateLimit.js";
export const coupleRoutes = Router();
const writeLimiter = rateLimit({ keyPrefix: "couple-write", max: 120, windowMs: 15 * 60 * 1000 });
coupleRoutes.use(requireAuth);
coupleRoutes.get("/room", getRoomController);
coupleRoutes.post("/room", writeLimiter, createRoomController);
coupleRoutes.post("/room/join", writeLimiter, joinRoomController);
coupleRoutes.patch("/room", writeLimiter, updateRoomController);
coupleRoutes.patch("/room/avatar", writeLimiter, updateRoomAvatarController);
coupleRoutes.get("/couple/summary", summaryController);
coupleRoutes.get("/couple/stats", statsController);
coupleRoutes.get("/game", getGameController);
coupleRoutes.post("/game/move", writeLimiter, gameMoveController);
coupleRoutes.post("/game/invite", writeLimiter, inviteGameController);
coupleRoutes.post("/game/accept", writeLimiter, acceptGameController);
coupleRoutes.post("/game/decline", writeLimiter, declineGameController);
coupleRoutes.post("/game/rps", writeLimiter, playRpsController);
coupleRoutes.post("/game/surrender", writeLimiter, surrenderGameController);
coupleRoutes.get("/memories", listMemoriesController);
coupleRoutes.post("/memories", writeLimiter, createMemoryController);
coupleRoutes.patch("/memories/:id", writeLimiter, updateMemoryController);
coupleRoutes.delete("/memories/:id", writeLimiter, deleteMemoryController);
coupleRoutes.get("/letters", listLettersController);
coupleRoutes.post("/letters", writeLimiter, createLetterController);
coupleRoutes.patch("/letters/:id", writeLimiter, updateLetterController);
coupleRoutes.patch("/letters/:id/open", writeLimiter, openLetterController);
coupleRoutes.delete("/letters/:id", writeLimiter, deleteLetterController);
coupleRoutes.get("/love-notes", listLettersController);
coupleRoutes.post("/love-notes", writeLimiter, createLetterController);
coupleRoutes.patch("/love-notes/:id/pin", writeLimiter, pinLoveNoteController);
coupleRoutes.patch("/love-notes/:id/open", writeLimiter, openLetterController);
coupleRoutes.delete("/love-notes/:id", writeLimiter, deleteLetterController);
coupleRoutes.get("/tasks", listTasksController);
coupleRoutes.post("/tasks", writeLimiter, createTaskController);
coupleRoutes.patch("/tasks/:id", writeLimiter, updateTaskController);
coupleRoutes.patch("/tasks/:id/done", writeLimiter, markTaskDoneController);
coupleRoutes.delete("/tasks/:id", writeLimiter, deleteTaskController);
coupleRoutes.get("/bucket-list", listBucketController);
coupleRoutes.post("/bucket-list", writeLimiter, createBucketController);
coupleRoutes.patch("/bucket-list/:id/toggle", writeLimiter, toggleBucketController);
coupleRoutes.delete("/bucket-list/:id", writeLimiter, deleteBucketController);
coupleRoutes.get("/wallet", listWalletController);
coupleRoutes.post("/wallet", writeLimiter, createWalletController);
coupleRoutes.delete("/wallet/:id", writeLimiter, deleteWalletController);
coupleRoutes.get("/challenges", listChallengesController);
coupleRoutes.post("/challenges", writeLimiter, createChallengeController);
coupleRoutes.patch("/challenges/:id/checkin", writeLimiter, checkinChallengeController);
coupleRoutes.delete("/challenges/:id", writeLimiter, deleteChallengeController);
coupleRoutes.get("/love-goals", listTasksController);
coupleRoutes.post("/love-goals", writeLimiter, createTaskController);
coupleRoutes.patch("/love-goals/:id", writeLimiter, updateTaskController);
coupleRoutes.delete("/love-goals/:id", writeLimiter, deleteTaskController);
coupleRoutes.get("/calendar-events", listCalendarEventsController);
coupleRoutes.post("/calendar-events", writeLimiter, createCalendarEventController);
coupleRoutes.patch("/calendar-events/:id", writeLimiter, updateCalendarEventController);
coupleRoutes.delete("/calendar-events/:id", writeLimiter, deleteCalendarEventController);
coupleRoutes.get("/music", listSongsController);
coupleRoutes.post("/music", writeLimiter, addSongController);
coupleRoutes.patch("/music/:id", writeLimiter, updateSongController);
coupleRoutes.delete("/music/:id", writeLimiter, removeSongController);
coupleRoutes.get("/questions/today", todayQuestionController);
coupleRoutes.post("/questions", writeLimiter, createRoomQuizController);
coupleRoutes.post("/questions/answers", writeLimiter, submitAnswerController);
coupleRoutes.post("/questions/:quizId/answers", writeLimiter, submitRoomQuizAnswerController);
coupleRoutes.get("/quiz-games", listQuizGamesController);
coupleRoutes.post("/quiz-games", writeLimiter, createQuizGameController);
coupleRoutes.get("/quiz-games/:gameId/play", getQuizGamePlayController);
coupleRoutes.get("/quiz-games/:gameId/report", getQuizGameReportController);
coupleRoutes.post("/quiz-games/:gameId/attempts", writeLimiter, submitQuizGameAttemptController);
coupleRoutes.get("/moods/today", todayMoodsController);
coupleRoutes.put("/moods/today", writeLimiter, setMoodController);
coupleRoutes.get("/albums", listAlbumsController);
coupleRoutes.post("/albums", writeLimiter, createAlbumController);
coupleRoutes.post("/albums/:albumId/photos", writeLimiter, addAlbumPhotoController);
coupleRoutes.delete("/albums/photos/:photoId", writeLimiter, deleteAlbumPhotoController);
coupleRoutes.get("/notifications", listNotificationsController);
